import { useState, useEffect } from "react";

function App() {
  const [tarefa, setTarefa] = useState("");
  const [lista, setLista] = useState(() => {
    const tarefasSalvas = localStorage.getItem("tarefas");
    return tarefasSalvas ? JSON.parse(tarefasSalvas) : [];
  });

  useEffect(() => {
    localStorage.setItem("tarefas", JSON.stringify(lista));
  }, [lista]);

  function adicionarTarefa() {
    if (tarefa.trim() === "") return;
    setLista([...lista, { texto: tarefa, concluida: false }]);
    setTarefa("");
  }

  function removerTarefa(index) {
    const novaLista = lista.filter((_, i) => i !== index);
    setLista(novaLista);
  }

  function toggleConcluida(index) {
    const novaLista = [...lista];
    novaLista[index].concluida = !novaLista[index].concluida;
    setLista(novaLista);
  }

  return (
    <div style={styles.container}>
      <h1 style={styles.titulo}>To-Do List</h1>

      <div style={styles.inputContainer}>
        <input
          style={styles.input}
          value={tarefa}
          onChange={(e) => setTarefa(e.target.value)}
          placeholder="Digite uma tarefa"
        />
        <button style={styles.adicionarBtn} onClick={adicionarTarefa}>
          Adicionar
        </button>
      </div>

      <ul style={styles.lista}>
        {lista.map((item, index) => (
          <li key={index} style={styles.item}>
            <span
              onClick={() => toggleConcluida(index)}
              style={{
                ...styles.textoTarefa,
                textDecoration: item.concluida ? "line-through" : "none",
                color: item.concluida ? "#999" : "#333",
              }}
            >
              {item.texto}
            </span>
            <button
              style={styles.removerBtn}
              onClick={() => removerTarefa(index)}
            >
              X
            </button>
          </li>
        ))}
      </ul>
    </div>
  );
}

const styles = {
  container: {
    maxWidth: 500,
    margin: "40px auto",
    padding: 20,
    fontFamily: "Arial, sans-serif",
    backgroundColor: "#f5f5f5",
    borderRadius: 8,
    boxShadow: "0 0 10px rgba(0,0,0,0.1)",
  },
  titulo: {
    textAlign: "center",
    color: "#333",
  },
  inputContainer: {
    display: "flex",
    gap: 10,
    marginBottom: 20,
  },
  input: {
    flex: 1,
    padding: 10,
    borderRadius: 4,
    border: "1px solid #ccc",
    fontSize: 16,
  },
  adicionarBtn: {
    padding: "10px 20px",
    backgroundColor: "#007bff",
    color: "#fff",
    border: "none",
    borderRadius: 4,
    cursor: "pointer",
    fontWeight: "bold",
  },
  lista: {
    listStyle: "none",
    padding: 0,
  },
  item: {
    display: "flex",
    justifyContent: "space-between",
    alignItems: "center",
    padding: "10px 0",
    borderBottom: "1px solid #ccc",
  },
  textoTarefa: {
    cursor: "pointer",
    fontSize: 16,
  },
  removerBtn: {
    backgroundColor: "#dc3545",
    color: "#fff",
    border: "none",
    padding: "5px 10px",
    borderRadius: 4,
    cursor: "pointer",
  },
};

export default App;
